/**
 * Strategy Marketplace Detail — Full strategy view with reputation breakdown.
 * RESEARCH AND REVIEW ONLY.
 */
import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import { SkeletonTablePage } from '../components/SkeletonUI';
import s from './StrategyMarketplaceDetailPage.module.css';

const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
};

function Metric({ label, value, color, large }) {
  return (
    <div className={s.metricCell}>
      <div
        className={`${s.metricValue} ${large ? s.metricValueLarge : s.metricValueNormal}`}
        style={{ color: color || T.text }}
      >
        {value}
      </div>
      <div className={s.metricLabel}>{label}</div>
    </div>
  );
}

function RepBar({ label, value, max = 1, color = T.blue }) {
  const pct = Math.min(Math.max(value / max, 0), 1) * 100;
  return (
    <div className={s.repBarRow}>
      <span className={s.repBarLabel}>{label}</span>
      <div className={s.repBarTrack}>
        <div className={s.repBarFill} style={{ width: `${pct}%`, background: color }} />
      </div>
      <span className={s.repBarValue}>{value.toFixed(2)}</span>
    </div>
  );
}

export default function StrategyMarketplaceDetailPage() {
  const { strategyId } = useParams();
  const navigate = useNavigate();
  usePageTitle(`Strategy: ${strategyId}`);

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchDetail = useCallback(async () => {
    const d = await api(`/api/marketplace/catalog/strategy/${strategyId}`);
    if (d) setData(d);
    setLoading(false);
  }, [strategyId]);

  useEffect(() => { fetchDetail(); }, [fetchDetail]);

  const doAction = async (action) => {
    await apiPost('/api/marketplace/catalog/action', { strategy_id: strategyId, action });
    fetchDetail();
  };

  if (loading) return <SkeletonTablePage title="Strategy Detail" metricCount={4} cols={5} rows={6} />;
  if (!data) return <div className={s.errorState}>Strategy not found.</div>;

  const rep = data.reputation || {};

  return (
    <div className={s.page}>
      {/* Back */}
      <button onClick={() => navigate('/strategy-marketplace')} className={s.backBtn}>
        ← Back to Marketplace
      </button>

      {/* Header */}
      <GlassPanel className={s.headerPanel}>
        <div className={s.headerRow}>
          <div>
            <h1 className={s.strategyTitle}>
              {data.strategy_name || data.strategy_id}
            </h1>
            <div className={s.strategyMeta}>
              {data.family} · {data.direction} · {data.asset_class}
              {data.generation > 0 && ` · Gen ${data.generation}`}
            </div>
            {data.summary && <p className={s.strategySummary}>{data.summary}</p>}
          </div>
          <div className={s.alphaScoreBlock}>
            <div
              className={s.alphaScoreValue}
              style={{ color: data.alpha_score >= 0.7 ? T.green : T.text }}
            >
              {(data.alpha_score || 0).toFixed(3)}
            </div>
            <div className={s.alphaScoreLabel}>Alpha Score</div>
          </div>
        </div>
      </GlassPanel>

      {/* Metrics Grid */}
      <div className={s.metricsGrid}>
        <GlassPanel><Metric label="Sharpe" value={(data.sharpe || 0).toFixed(2)} color={data.sharpe >= 1.5 ? T.green : T.text} /></GlassPanel>
        <GlassPanel><Metric label="Profit Factor" value={(data.profit_factor || 0).toFixed(2)} color={data.profit_factor >= 1.4 ? T.green : T.text} /></GlassPanel>
        <GlassPanel><Metric label="Win Rate" value={`${(data.win_rate || 0).toFixed(0)}%`} /></GlassPanel>
        <GlassPanel><Metric label="Max DD" value={`${((data.max_drawdown || 0) * 100).toFixed(1)}%`} color={data.max_drawdown < -0.25 ? T.red : T.text} /></GlassPanel>
        <GlassPanel><Metric label="Trades" value={data.trade_count || 0} /></GlassPanel>
        <GlassPanel><Metric label="Reputation" value={(rep.reputation_score || 0).toFixed(3)} color={rep.reputation_score >= 0.7 ? T.green : T.text} /></GlassPanel>
      </div>

      <div className={s.twoCol}>
        {/* Reputation Breakdown */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>REPUTATION BREAKDOWN</h3>
          <RepBar label="Research Quality" value={rep.research_quality || 0} color={T.blue} />
          <RepBar label="Walk-Forward" value={rep.walk_forward || 0} color={T.green} />
          <RepBar label="Regime Stability" value={rep.regime_stability || 0} color={T.amber} />
          <RepBar label="Analyst Confidence" value={rep.analyst_confidence || 0} color={T.purple} />
          <RepBar label="Engagement" value={rep.engagement || 0} color={T.blue} />
          <RepBar label="Tracked Perf." value={rep.tracked_performance || 0} color={T.green} />
          <RepBar label="Freshness" value={rep.freshness_bonus || 0} color={T.amber} />
          {(rep.overfit_penalty || 0) > 0 && (
            <div className={s.penaltyRed}>
              Overfit penalty: -{rep.overfit_penalty.toFixed(3)}
            </div>
          )}
          {(rep.staleness_penalty || 0) > 0 && (
            <div className={s.penaltyAmber}>
              Staleness penalty: -{rep.staleness_penalty.toFixed(3)}
            </div>
          )}
        </GlassPanel>

        {/* Strengths & Risks */}
        <div className={s.strengthsRisksCol}>
          <GlassPanel className={s.strengthsPanel}>
            <h3 className={s.sectionTitleGreen}>STRENGTHS</h3>
            {(data.strengths || []).map((item, i) => (
              <div key={i} className={s.listItemStrength}>+ {item}</div>
            ))}
          </GlassPanel>
          <GlassPanel>
            <h3 className={s.sectionTitleRed}>RISKS</h3>
            {(data.risks || []).map((r, i) => (
              <div key={i} className={s.listItemRisk}>- {r}</div>
            ))}
          </GlassPanel>
        </div>
      </div>

      {/* Lineage */}
      {data.lineage && Object.keys(data.lineage).length > 0 && (
        <GlassPanel className={s.lineagePanel}>
          <h3 className={s.sectionTitle}>LINEAGE</h3>
          {Object.entries(data.lineage).map(([k, v]) => (
            <span key={k} className={s.lineageItem}>{k}: {v}</span>
          ))}
        </GlassPanel>
      )}

      {/* Engagement */}
      <GlassPanel className={s.engagementPanel}>
        <div className={s.engagementRow}>
          <span>Views: {data.view_count || 0}</span>
          <span>Watchlists: {data.watchlist_count || 0}</span>
          <span>Bookmarks: {data.bookmark_count || 0}</span>
          <span>Paper: {data.paper_candidate_count || 0}</span>
          <span>Live: {data.live_candidate_count || 0}</span>
        </div>
      </GlassPanel>

      {/* Actions */}
      <div className={s.actionsRow}>
        {[
          { action: 'add_watchlist', label: 'Add to Watchlist', color: T.green },
          { action: 'mark_paper_candidate', label: 'Paper Candidate', color: T.amber },
          { action: 'mark_live_candidate', label: 'Live Candidate Review', color: T.purple },
          { action: 'add_bookmark', label: 'Bookmark', color: T.textSec },
        ].map(btn => (
          <button
            key={btn.action}
            onClick={() => doAction(btn.action)}
            className={s.actionBtn}
            style={{
              background: btn.color + '18',
              border: `1px solid ${btn.color}55`,
              color: btn.color,
            }}
          >
            {btn.label}
          </button>
        ))}
      </div>
    </div>
  );
}
